var numSubarraysWithSum = function(nums, goal) {
    const seen = new Map();
    seen.set(0, 1);
    let running = 0, count = 0;
    for (const x of nums) {
        running += x;
        count += seen.get(running - goal) || 0;
        seen.set(running, (seen.get(running) || 0) + 1);
    }
    return count;
};
